// Extract tool_use blocks from Claude API response
const response = $input.first().json;
const content = response.content || [];

const toolCalls = content
  .filter(block => block.type === 'tool_use')
  .map(block => ({
    tool: block.name,
    depth: $('Delegation Depth Counter').item.json.depth || 1,
    action: 'tool_call',
    agent_id: 'agent_orchestrator',
    metadata: {
      input_keys: Object.keys(block.input || {}),
      model: response.model
    }
  }));

return toolCalls.map(tc => ({ json: tc }));

// Accumulate metrics for paper figures
const metrics = $input.first().json;
return [{
  json: {
    step: metrics.step,
    tool: metrics.tool,
    depth: metrics.depth,
    D_hat: metrics.D_hat,
    D_t: metrics.D_t,
    D_c: metrics.D_c,
    D_l: metrics.D_l,
    enforcement: metrics.enforcement,
    anomaly: metrics.anomaly,
    timestamp: new Date().toISOString()
  }
}];

const m = $input.first().json;
console.log(`[IML ALERT] D̂=${m.D_hat} at step ${m.step}  enforcement=${m.enforcement}`);
return [{ json: { alert: true, D_hat: m.D_hat, step: m.step } }];
